### Optimize Payload CMS Field Access on Large Arrays with Context Caching (TypeScript)

Source: https://github.com/payloadcms/payload/blob/main/tools/claude-plugin/skills/payload/reference/ACCESS-CONTROL-ADVANCED.md

Illustrates a performance pitfall when using asynchronous access checks on fields within large arrays in Payload CMS, where the async call runs for every array item. The optimized solution demonstrates how to cache the result of an expensive check once within `req.context` and reuse it for all array items, significantly improving read performance.

```typescript
// ❌ Slow: Complex access on array fields
const arrayField: ArrayField = {
  name: 'items',
  type: 'array',
  fields: [
    {
      name: 'secretData',
      type: 'text',
      access: {
        read: async ({ req }) => {
          // Async call runs for EVERY array item
          const result = await expensiveCheck()
          return result
        },
      },
    },
  ],
}

```

```typescript
// ✅ Fast: Simple checks or cache result
const optimizedArrayField: ArrayField = {
  name: 'items',
  type: 'array',
  fields: [
    {
      name: 'secretData',
      type: 'text',
      access: {
        read: ({ req: { user }, context }) => {
          // Cache once, reuse for all items
          if (context.canReadSecret === undefined) {
            context.canReadSecret = user?.roles?.includes('admin')
          }
          return context.canReadSecret
        },
      },
    },
  ],
}

```

